 LAYER
    NAME "OGF_preCarto_seuil70"
    TYPE RASTER
    STATUS ON

    DATA "STATUS_MIX_q70_DLG.tif"
    PROJECTION
        "init=epsg:31370"
    END

    PROCESSING "BANDS=1"
    CLASSITEM "[pixel]"

    CLASS
        NAME "OGF potentielle"
        EXPRESSION "1"
        STYLE
            COLOR 0 0 0
        END
    END

    CLASS
        NAME "feuillus sur forêt ancienne pas mature"
        EXPRESSION "2"
        STYLE
            COLOR 255 255 255
            OPACITY 0
        END
    END

    METADATA
        "wms_title" "OGF precarto avec seuil de 70"
        "wms_srs"   "EPSG:31370"
    END
END


